THREE_PHASE_COMMIT
BEGIN
 // Phase 1: CanCommit
 coordinator.SEND CAN-COMMIT to all participants
 participants.SEND YES/NO to coordinator

 IF all responses == YES THEN
 // Phase 2: PreCommit
 coordinator.SEND PRE-COMMIT to all participants
 participants.SEND ACK to coordinator

 // Phase 3: DoCommit
 coordinator.SEND DO-COMMIT to all participants
 participants.COMMIT transaction
 participants.SEND ACK to coordinator
 ELSE
 // Abort case
 coordinator.SEND GLOBAL-ABORT to all participants
 participants.ABORT transaction
 END IF

 // Handle coordinator failure at each phase
 IF participant times out THEN
 // In PreCommit: know decision was commit, proceed to commit
 // In DoCommit: commit the transaction
 // In CanCommit: abort the transaction
 END IF
END
